-- Fuzzy customer matching for the PLM/ERP (ColdLion) import.
--
-- Why
-- ---
-- When ColdLion sends a customer, deciding "is this an existing potential
-- customer CRM/PM already created, or a brand-new one?" cannot be a
-- character-for-character name match. ERP and CRM spell the same company
-- differently ("Acme, Inc." vs "ACME Incorporated"). So matching is fuzzy.
--
-- Strategy (core.match_customer), strongest signal first:
--   1. exact normalized name           -> confident, activate that row in place
--   2. exact domain (from ERP email)    -> confident, activate that row in place
--   3. trigram name similarity >= 0.85  -> confident, activate that row in place
--   4. trigram name similarity in [0.55, 0.85) -> AMBIGUOUS: do NOT auto-merge.
--      Create the ERP customer as its own row and file an ingest.dedupe_candidate
--      so a human can confirm/merge. Silent auto-merge on a weak match would
--      corrupt the shared hub; silent duplicate-create would fragment history.
-- Activation to is_potential = false happens automatically via the
-- core.sync_customer_potential trigger when the ERP source ref is attached.
--
-- Thresholds are parameters on core.match_customer so they can be tuned without
-- touching the import.

create extension if not exists pg_trgm with schema extensions;

create index if not exists core_customer_normalized_name_trgm_idx
  on core.customer using gin (normalized_name extensions.gin_trgm_ops);

-- ---------------------------------------------------------------------------
-- core.match_customer — reusable entity resolution for incoming customers.
-- Returns exactly one row: match_id (confident link, may be null) and, when the
-- best candidate is only a mid-band fuzzy match, review_id/review_sim instead.
-- ---------------------------------------------------------------------------
create or replace function core.match_customer(
  p_name text,
  p_domain text default null,
  match_threshold real default 0.85,
  review_threshold real default 0.55
)
returns table (match_id uuid, review_id uuid, review_sim real)
language plpgsql
stable
security definer
set search_path = core, extensions, public
as $fn$
declare
  v_norm   text := lower(regexp_replace(coalesce(p_name, ''), '\s+', ' ', 'g'));
  v_domain text := lower(nullif(btrim(coalesce(p_domain, '')), ''));
  v_id  uuid;
  v_sim real;
begin
  match_id := null; review_id := null; review_sim := null;
  if v_norm = '' then return next; return; end if;

  -- 1. exact normalized name
  select id into v_id from core.customer where normalized_name = v_norm
    order by created_at limit 1;
  if v_id is not null then match_id := v_id; return next; return; end if;

  -- 2. exact domain
  if v_domain is not null then
    select id into v_id from core.customer
      where domain is not null and lower(domain) = v_domain
      order by created_at limit 1;
    if v_id is not null then match_id := v_id; return next; return; end if;
  end if;

  -- 3/4. best trigram name match, banded
  select id, extensions.similarity(normalized_name, v_norm)
    into v_id, v_sim
  from core.customer
  where normalized_name % v_norm
  order by extensions.similarity(normalized_name, v_norm) desc, created_at
  limit 1;

  if v_id is not null and v_sim >= match_threshold then
    match_id := v_id;                          -- confident auto-link
  elsif v_id is not null and v_sim >= review_threshold then
    review_id := v_id; review_sim := v_sim;    -- ambiguous -> human review
  end if;
  return next;
end;
$fn$;

comment on function core.match_customer(text, text, real, real) is
  'Resolves an incoming customer (name + optional domain) to an existing core.customer. Returns a confident match_id, or a mid-band review_id/review_sim to be filed in ingest.dedupe_candidate. Used by plm.import_master_data.';

revoke all on function core.match_customer(text, text, real, real) from public;
grant execute on function core.match_customer(text, text, real, real) to service_role;

-- ---------------------------------------------------------------------------
-- Recreate plm.import_master_data to use core.match_customer and to file
-- ambiguous matches into ingest.dedupe_candidate. Body is otherwise identical to
-- the core.customer version in 20260625120000_core_company_rename_customer.sql.
-- ---------------------------------------------------------------------------
create or replace function plm.import_master_data(
  licensors_payload jsonb,
  customers_payload jsonb
)
returns table (
  sync_run_id uuid,
  licensors_seen integer,
  properties_seen integer,
  customers_seen integer,
  raw_records_upserted integer
)
language plpgsql
security definer
set search_path = app, core, ingest, plm, extensions, public
as $$
declare
  sync_id uuid;
  licensor_row jsonb;
  property_row jsonb;
  customer_row jsonb;
  sanitized jsonb;
  v_source_id text;
  v_source_code text;
  v_source_name text;
  status_value app.entity_status;
  core_company_id uuid;
  v_match_id uuid;
  v_review_id uuid;
  v_review_sim real;
  v_erp_domain text;
  core_licensor_id uuid;
  core_property_id uuid;
  parent_core_licensor_id uuid;
  licensor_count integer := 0;
  property_count integer := 0;
  customer_count integer := 0;
  raw_count integer := 0;
begin
  if jsonb_typeof(coalesce(licensors_payload, '[]'::jsonb)) <> 'array' then
    raise exception 'licensors_payload must be a JSON array';
  end if;

  if jsonb_typeof(coalesce(customers_payload, '[]'::jsonb)) <> 'array' then
    raise exception 'customers_payload must be a JSON array';
  end if;

  insert into ingest.sync_run (
    source_system,
    source_name,
    status,
    started_at,
    metadata
  )
  values (
    'designflow_plm',
    'plm_master_data_api',
    'running',
    now(),
    jsonb_build_object(
      'licensors_endpoint', 'getLicensorsWithProperties',
      'customers_endpoint', 'getCustomers'
    )
  )
  returning id into sync_id;

  for customer_row in
    select value
    from jsonb_array_elements(coalesce(customers_payload, '[]'::jsonb))
  loop
    v_source_id := nullif(customer_row ->> 'customers_id', '');
    v_source_code := nullif(customer_row ->> 'customers_code', '');
    v_source_name := nullif(customer_row ->> 'customers_name', '');
    sanitized := customer_row - 'customers_passw';

    if v_source_id is null or v_source_name is null then
      continue;
    end if;

    customer_count := customer_count + 1;
    status_value := case
      when upper(coalesce(customer_row ->> 'customers_status', '')) = 'ACTIVE' then 'active'::app.entity_status
      else 'inactive'::app.entity_status
    end;

    select csr.company_id
    into core_company_id
    from core.company_source_ref csr
    where csr.source_system = 'designflow_plm'
      and csr.source_table = 'customers'
      and csr.source_id = (customer_row ->> 'customers_id');

    -- Fuzzy entity resolution: exact name -> exact domain -> high-similarity name.
    -- A mid-band similarity is NOT auto-merged; it is flagged for human review.
    if core_company_id is null then
      v_erp_domain := lower(split_part(nullif(customer_row ->> 'customers_email', ''), '@', 2));
      select m.match_id, m.review_id, m.review_sim
        into v_match_id, v_review_id, v_review_sim
      from core.match_customer(v_source_name, v_erp_domain) m;
      core_company_id := v_match_id;
    end if;

    if core_company_id is null then
      insert into core.customer (
        name,
        company_type,
        status,
        phone,
        metadata
      )
      values (
        v_source_name,
        'customer',
        status_value,
        nullif(customer_row ->> 'customers_phonenum', ''),
        jsonb_build_object(
          'plm_customer_code', v_source_code,
          'plm_import_source', 'designflow_plm'
        )
      )
      returning id into core_company_id;
    else
      update core.customer
      set name = v_source_name,
          status = status_value,
          phone = coalesce(nullif(customer_row ->> 'customers_phonenum', ''), phone),
          metadata = metadata
            || jsonb_build_object(
              'plm_customer_code', v_source_code,
              'plm_import_source', 'designflow_plm'
            )
      where id = core_company_id;
    end if;

    insert into core.company_source_ref (
      company_id,
      source_system,
      source_table,
      source_id,
      source_code,
      source_name,
      confidence,
      raw
    )
    values (
      core_company_id,
      'designflow_plm',
      'customers',
      v_source_id,
      v_source_code,
      v_source_name,
      'verified',
      sanitized
    )
    on conflict (source_system, source_table, source_id) do update
    set company_id = excluded.company_id,
        source_code = excluded.source_code,
        source_name = excluded.source_name,
        confidence = excluded.confidence,
        raw = excluded.raw;

    if v_review_id is not null then
      insert into ingest.dedupe_candidate (
        entity_schema, entity_table, left_entity_id, right_entity_id,
        source_system, confidence, reason, raw
      )

